import re
from src.models import GuardrailCheck


def check_patch(patch_text: str, brand: str) -> list[GuardrailCheck]:
    """Evaluate a unified diff against the brand's AGENTS.md rules.

    Returns one GuardrailCheck per rule regardless of pass/fail.
    brand is present for future multi-brand AGENTS.md routing.
    """
    added_lines = [
        line[1:]
        for line in patch_text.splitlines()
        if line.startswith("+") and not line.startswith("+++")
    ]
    return [
        _check_r1(added_lines),
        _check_r2(added_lines),
        _check_r3(added_lines),
        _check_r4(added_lines),
        _check_r5(added_lines),
    ]


def _check_r1(lines: list[str]) -> GuardrailCheck:
    """R1 — Absolute imports only (WARN)."""
    for line in lines:
        if re.search(r"from\s+\.", line):
            return GuardrailCheck(
                ruleId="R1",
                severity="WARN",
                result="fail",
                reason="Relative import detected — use absolute imports per AGENTS.md R1",
            )
    return GuardrailCheck(
        ruleId="R1",
        severity="WARN",
        result="pass",
        reason="All imports are absolute per AGENTS.md R1",
    )


def _check_r2(lines: list[str]) -> GuardrailCheck:
    """R2 — No os.system / subprocess (BLOCK)."""
    for line in lines:
        if re.search(r"os\.system\(|subprocess\.", line):
            return GuardrailCheck(
                ruleId="R2",
                severity="BLOCK",
                result="fail",
                reason="Unsafe shell call detected — requires security review per AGENTS.md R2",
            )
    return GuardrailCheck(
        ruleId="R2",
        severity="BLOCK",
        result="pass",
        reason="No unsafe shell calls per AGENTS.md R2",
    )


def _check_r3(lines: list[str]) -> GuardrailCheck:
    """R3 — Public functions have docstrings (WARN)."""
    for i, line in enumerate(lines):
        if re.match(r"def [a-zA-Z][^_]", line):
            next_line = lines[i + 1] if i + 1 < len(lines) else ""
            if '"""' not in next_line:
                return GuardrailCheck(
                    ruleId="R3",
                    severity="WARN",
                    result="fail",
                    reason="Public function missing docstring per AGENTS.md R3",
                )
    return GuardrailCheck(
        ruleId="R3",
        severity="WARN",
        result="pass",
        reason="Public functions have docstrings per AGENTS.md R3",
    )


def _check_r4(lines: list[str]) -> GuardrailCheck:
    """R4 — No print() (BLOCK)."""
    for line in lines:
        if re.search(r"\bprint\s*\(", line):
            return GuardrailCheck(
                ruleId="R4",
                severity="BLOCK",
                result="fail",
                reason="print() call detected — use efood.logging per AGENTS.md R4",
            )
    return GuardrailCheck(
        ruleId="R4",
        severity="BLOCK",
        result="pass",
        reason="No print() calls — logging used correctly per AGENTS.md R4",
    )


def _check_r5(lines: list[str]) -> GuardrailCheck:
    """R5 — No direct requests (BLOCK)."""
    for line in lines:
        if re.search(r"\brequests\.(get|post|put|delete|patch|head|options)\b", line):
            return GuardrailCheck(
                ruleId="R5",
                severity="BLOCK",
                result="fail",
                reason="Direct requests call detected — use efood.http_client per AGENTS.md R5",
            )
    return GuardrailCheck(
        ruleId="R5",
        severity="BLOCK",
        result="pass",
        reason="No direct HTTP calls — efood.http_client used per AGENTS.md R5",
    )

"""LLM integration with just-in-time AGENTS.md context injection."""
import logging
import os
from pathlib import Path
from typing import Any

import anthropic

logger = logging.getLogger(__name__)


def _read_agents(brand: str) -> str:
    """Read AGENTS.md for the given brand at call time (just-in-time)."""
    return Path(f"{brand}/AGENTS.md").read_text()


def _call(brand: str, prompt: str, tool_schema: dict) -> Any:
    """Call Claude with tool_use to force valid structured JSON output."""
    agents_content = _read_agents(brand)
    api_key = os.environ.get("ANTHROPIC_API_KEY", "")
    if not api_key:
        return None  # caller handles mock

    system = (
        f"You are a code change planner for the {brand} brand. "
        f"Follow these Engineering Manifesto rules:\n\n{agents_content}"
    )
    client = anthropic.Anthropic(api_key=api_key)
    response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=4096,
        system=system,
        tools=[{"name": "output", "description": "Return the result", "input_schema": tool_schema}],
        tool_choice={"type": "tool", "name": "output"},
        messages=[{"role": "user", "content": prompt}],
    )
    return response.content[0].input


def generate(prompt: str, brand: str, schema: type) -> dict:
    """Return a single schema-validated dict from the LLM."""
    result = _call(brand, prompt, schema.model_json_schema())
    if result is None:
        return _mock(schema)
    logger.debug("LLM response for %s: %s", schema.__name__, result)
    return result


def generate_list(prompt: str, brand: str, schema: type) -> list[dict]:
    """Return a list of schema-validated dicts from the LLM."""
    list_schema = {
        "type": "object",
        "properties": {"items": {"type": "array", "items": schema.model_json_schema()}},
        "required": ["items"],
    }
    result = _call(brand, prompt, list_schema)
    if result is None:
        return [_mock(schema)]
    logger.debug("LLM list response for %s: %s", schema.__name__, result)
    return result["items"]


def _mock(schema: type) -> dict:
    """Deterministic fallback when ANTHROPIC_API_KEY is absent."""
    name = schema.__name__
    if name == "PlanStepInput":
        return {"description": "Add apply_discount function", "target_files": ["pricing/discount.py"]}
    if name == "PatchProposalInput":
        return {
            "diff": (
                "+from .utils import calc\n"
                "+def apply_discount(order, pct):\n"
                '+    print(f"Discount applied: {pct}")\n'
                "+    requests.get(provider_url)\n"
            ),
        }
    return {k: "" for k in schema.model_fields}

