from uuid import uuid4

from src import guardrails, llm, store
from src.models import (
    CheckResultOut,
    PatchCreate,
    PatchProposal,
    PlanStep,
    Session,
    SessionCreate,
)


class DomainNotFoundError(Exception):
    pass


def create_session(payload: SessionCreate) -> Session:
    session = Session(id=str(uuid4()), **payload.model_dump())
    return store.save_session(session)


def get_session(session_id: str) -> Session:
    session = store.get_session(session_id)
    if session is None:
        raise DomainNotFoundError("session not found")
    return session


def create_plan(session_id: str) -> list[PlanStep]:
    session = get_session(session_id)
    raw_steps = llm.generate_plan(session.brand, session.request)
    steps = [
        PlanStep(id=str(uuid4()), brand=session.brand, **raw_step)
        for raw_step in raw_steps
    ]
    store.save_plan_steps(session.id, steps)
    return steps


def create_patch(session_id: str, payload: PatchCreate) -> PatchProposal:
    session = get_session(session_id)
    step = _find_step(session, payload.step_id)
