    diff = llm.generate_patch(session.brand, session.request, step_input)
    patch = PatchProposal(
        id=str(uuid4()),
        brand=session.brand,
        session_id=session.id,
        step_id=step.id,
        diff=diff,
    )
    return store.save_patch(session.id, patch)


