    patch = store.get_patch(patch_id)
    if patch is None:
        raise DomainNotFoundError("patch not found")
    checks = guardrails.run_checks(patch.diff)
    mergeable = all(check.severity != "BLOCK" for check in checks)
    store.update_patch_checks(patch.id, checks, mergeable)
    return CheckResultOut(patch_id=patch.id, mergeable=mergeable, checks=checks)


def _find_step(session: Session, step_id: str) -> PlanStep:
    for step in session.plan_steps:
        if step.id == step_id:
            return step
    raise DomainNotFoundError("step not found")

